const express = require('express');
const app = express();
const bodyParser = require('body-parser');

app.use(bodyParser.json());

// Database schema to store player data
const db = {
  players: {}
};

// Function to award rewards based on client-reported metrics
function awardRewards(playerId, score, time) {
  const levelCompleted = Math.floor(score / 100);
  let reward;

  if (levelCompleted >= 5 && time <= 60) {
    reward = 'gold';
  } else if (levelCompleted >= 10 && time <= 120) {
    reward = 'silver';
  } else if (levelCompleted >= 15 && time <= 180) {
    reward = 'bronze';
  }

  return reward;
}

// Endpoint to complete levels and claim rewards
app.post('/complete-level', (req, res) => {
  const { playerId, score, time } = req.body;

  // Validate client-reported metrics
  if (!playerId || !score || !time) {
    return res.status(400).send({ error: 'Invalid request' });
  }

  // Award rewards based on client-reported metrics
  const reward = awardRewards(playerId, score, time);

  // Update player data in database
  db.players[playerId].levelsCompleted += 1;
  db.players[playerId].score += score;
  db.players[playerId].time += time;

  // Return reward to client
  res.send({ reward });
});

// Endpoint to check if a player has completed a level
app.get('/check-level', (req, res) => {
  const { playerId } = req.query;

  // Validate player ID
  if (!playerId) {
    return res.status(400).send({ error: 'Invalid request' });
  }

  // Check if player has completed the level
  const levelsCompleted = db.players[playerId].levelsCompleted;
  const score = db.players[playerId].score;

  if (levelsCompleted >= 5 && score >= 500) {
    return res.send({ levelCompleted: true });
  } else {
    return res.send({ levelCompleted: false });
  }
});

// Endpoint to check for game bot detection bypass
app.get('/check-bot', (req, res) => {
  const { playerId } = req.query;

  // Validate player ID
  if (!playerId) {
    return res.status(400).send({ error: 'Invalid request' });
  }

  // Check for game bot detection bypass
  if (db.players[playerId].levelsCompleted > 10 && db.players[playerId].score > 1000) {
    return res.send({ botDetected: true });
  } else {
    return res.send({ botDetected: false });
  }
});

